exercises.solution_code:
#include <iostream>

int main() {
    constexpr int cm_per_m = 100;
    constexpr int mm_per_m = 1000;
    constexpr long long um_per_m = 1000000LL;

    int meters = 0;
    std::cin >> meters;

    int cm = meters * cm_per_m;
    int mm = meters * mm_per_m;
    long long um = meters * um_per_m;

    std::cout << "Meters: "      << meters << "\n";
    std::cout << "Centimeters: " << cm     << "\n";
    std::cout << "Millimeters: " << mm     << "\n";
    std::cout << "Micrometers: " << um     << "\n";

    return 0;
}

