exercises.solution_code:
#include <iostream>

int main() {
    constexpr int bits_per_channel  = 8;
    constexpr int channels_per_pixel = 3;
    constexpr int bits_per_pixel    = bits_per_channel * channels_per_pixel; // 24, folded at compile time

    int width = 0;
    int height = 0;
    std::cin >> width >> height;

    long long total_pixels = static_cast<long long>(width) * height;
    long long total_bits   = total_pixels * bits_per_pixel;
    long long total_bytes  = total_bits / 8;

    std::cout << "Resolution: "    << width << "x" << height << "\n";
    std::cout << "Total pixels: "  << total_pixels            << "\n";
    std::cout << "Bits per pixel: "<< bits_per_pixel          << "\n";
    std::cout << "Total bits: "    << total_bits              << "\n";
    std::cout << "Total bytes: "   << total_bytes             << "\n";

    return 0;
}
